#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct JsonPathAssertion {
    pub path: String,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub equals: Option<serde_json::Value>,
    #[serde(default, rename = "notEquals", skip_serializing_if = "Option::is_none")]
    pub not_equals: Option<serde_json::Value>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub exists: Option<bool>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub contains: Option<serde_json::Value>,
    #[serde(
        default,
        rename = "greaterThan",
        skip_serializing_if = "Option::is_none"
    )]
    pub greater_than: Option<serde_json::Value>,
    #[serde(default, rename = "lessThan", skip_serializing_if = "Option::is_none")]
    pub less_than: Option<serde_json::Value>,
    #[serde(
        default,
        rename = "countEquals",
        skip_serializing_if = "Option::is_none"
    )]
    pub count_equals: Option<u64>,
    #[serde(
        default,
        rename = "countGreaterThan",
        skip_serializing_if = "Option::is_none"
    )]
    pub count_greater_than: Option<u64>,
    #[serde(
        default,
        rename = "countLessThan",
        skip_serializing_if = "Option::is_none"
    )]
    pub count_less_than: Option<u64>,
    /// Assert the array at `path` contains at least one element whose `type`
    /// field equals this value. Lets event-bearing evidence assert a concrete
    /// event type instead of only counting unrelated events.
    #[serde(
        default,
        rename = "containsType",
        skip_serializing_if = "Option::is_none"
    )]
    pub contains_type: Option<String>,
}
/// Reject scenario `steps`/`assertions` entries that carry more than one key.
/// These are untagged enums, so a map with two action/target keys would
/// otherwise deserialize as the first matching variant and silently drop the
/// rest. Parsed against the raw YAML so it runs before the lossy typed parse.
pub fn validate_single_key_scenario_entries(input: &str) -> Result<()> {
    let value: serde_yaml::Value = match serde_yaml::from_str(input) {
        Ok(value) => value,
        // Let the typed parse surface the real syntax error.
        Err(_) => return Ok(()),
    };
    let Some(scenarios) = value.get("scenarios").and_then(|value| value.as_sequence()) else {
        return Ok(());
    };
    for (scenario_index, scenario) in scenarios.iter().enumerate() {
        for (field, label) in [("steps", "step"), ("assertions", "assertion")] {
            let Some(entries) = scenario.get(field).and_then(|value| value.as_sequence()) else {
                continue;
            };
            for (entry_index, entry) in entries.iter().enumerate() {
                if let Some(mapping) = entry.as_mapping() {
                    if mapping.len() != 1 {
                        return Err(anyhow!(
                            "scenario[{scenario_index}] {label}[{entry_index}] must contain exactly one key, found {}",
                            mapping.len()
                        ));
                    }
                }
            }
        }
    }
    Ok(())
}
pub const SCENARIO_PACK_SCHEMA_VERSION: &str = "scenario-pack-v1";
#[derive(Debug, Clone, Deserialize, Serialize, PartialEq)]
#[serde(deny_unknown_fields)]
pub struct ScenarioPack {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub id: String,
    pub description: String,
    pub seed: String,
    pub scenes: Vec<String>,
    #[serde(rename = "scenarioGroups")]
    pub scenario_groups: Vec<ScenarioPackGroup>,
}
#[derive(Debug, Clone, Deserialize, Serialize, PartialEq)]
#[serde(deny_unknown_fields)]
pub struct ScenarioPackGroup {
    pub id: String,
    pub description: String,
    pub scenarios: Vec<Scenario>,
}
impl ScenarioPack {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let pack: ScenarioPack =
            serde_json::from_str(input).context("failed to parse Scenario Pack JSON")?;
        pack.validate()?;
        Ok(pack)
    }

    pub fn from_path(path: impl AsRef<Path>) -> Result<Self> {
        let path = path.as_ref();
        let input = fs::read_to_string(path)
            .with_context(|| format!("failed to read scenario pack {}", path.display()))?;
        Self::from_json_str(&input)
            .with_context(|| format!("failed to parse scenario pack {}", path.display()))
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != SCENARIO_PACK_SCHEMA_VERSION {
            return Err(anyhow!(
                "scenario pack schemaVersion must be {SCENARIO_PACK_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("scenario pack id", &self.id)?;
        require_text("scenario pack description", &self.description)?;
        validate_project_manifest_path("scenario pack seed", &self.seed)?;
        if self.scenes.is_empty() {
            return Err(anyhow!("scenario pack scenes must not be empty"));
        }
        validate_project_path_list("scenario pack scenes", &self.scenes)?;
        if self.scenario_groups.is_empty() {
            return Err(anyhow!("scenario pack scenarioGroups must not be empty"));
        }
        let mut group_ids = BTreeSet::new();
        let mut scenario_ids = BTreeSet::new();
        for (group_index, group) in self.scenario_groups.iter().enumerate() {
            group.validate(group_index, &mut scenario_ids)?;
            if !group_ids.insert(group.id.clone()) {
                return Err(anyhow!("duplicate scenario pack group id: {}", group.id));
            }
        }
        Ok(())
    }

    pub fn ordered_scenario_ids(&self) -> Vec<String> {
        self.scenario_groups
            .iter()
            .flat_map(|group| group.scenarios.iter())
            .map(|scenario| scenario.id.clone())
            .collect()
    }
}
