#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct RegressionPromotionTarget {
    #[serde(rename = "projectManifestPath")]
    pub project_manifest_path: String,
    #[serde(rename = "scenarioPackId")]
    pub scenario_pack_id: String,
    #[serde(rename = "scenarioPackPath")]
    pub scenario_pack_path: String,
    #[serde(rename = "scenarioGroupId")]
    pub scenario_group_id: String,
}
impl RegressionPromotionSourceRun {
    pub fn validate(&self) -> Result<()> {
        require_text("regression promotion sourceRun runId", &self.run_id)?;
        validate_relative_artifact_path("regression promotion sourceRun runDir", &self.run_dir)?;
        if !self.run_dir.starts_with("runs/") {
            return Err(anyhow!(
                "regression promotion sourceRun runDir must point to runs/"
            ));
        }
        validate_relative_artifact_path(
            "regression promotion sourceRun verdictPath",
            &self.verdict_path,
        )?;
        if self.verdict_path != "verdict.json" {
            return Err(anyhow!(
                "regression promotion sourceRun verdictPath must be verdict.json"
            ));
        }
        Ok(())
    }
}
impl RegressionPromotionTarget {
    pub fn validate(&self) -> Result<()> {
        validate_project_manifest_path(
            "regression promotion target projectManifestPath",
            &self.project_manifest_path,
        )?;
        if Path::new(&self.project_manifest_path)
            .file_name()
            .and_then(|name| name.to_str())
            != Some(PROJECT_MANIFEST_FILE_NAME)
        {
            return Err(anyhow!(
                "regression promotion target projectManifestPath file name must be {PROJECT_MANIFEST_FILE_NAME}"
            ));
        }
        validate_path_component(
            "regression promotion target scenarioPackId",
            &self.scenario_pack_id,
        )?;
        validate_project_manifest_path(
            "regression promotion target scenarioPackPath",
            &self.scenario_pack_path,
        )?;
        validate_path_component(
            "regression promotion target scenarioGroupId",
            &self.scenario_group_id,
        )?;
        Ok(())
    }
}
pub fn scenario_assertions_from_failed_result(
    scenario_result: &serde_json::Value,
) -> Result<Vec<ScenarioAssertion>> {
    let assertion_values = scenario_result
        .get("assertions")
        .and_then(|value| value.as_array())
        .ok_or_else(|| anyhow!("regression promotion scenario result assertions are missing"))?;
    let mut assertions = Vec::new();
    for assertion in assertion_values {
        if assertion.get("passed").and_then(|value| value.as_bool()) == Some(false) {
            assertions.push(regression_assertion_from_result(assertion)?);
        }
    }
    if assertions.is_empty() {
        return Err(anyhow!(
            "regression promotion scenario result has no failed assertions to promote"
        ));
    }
    Ok(assertions)
}
pub fn regression_assertion_from_result(
    assertion: &serde_json::Value,
) -> Result<ScenarioAssertion> {
    let target = assertion
        .get("target")
        .and_then(|value| value.as_str())
        .ok_or_else(|| anyhow!("regression promotion assertion target is missing"))?;
    let path = assertion
        .get("path")
        .and_then(|value| value.as_str())
        .ok_or_else(|| anyhow!("regression promotion assertion path is missing"))?;
    let operator = assertion
        .get("operator")
        .and_then(|value| value.as_str())
        .ok_or_else(|| anyhow!("regression promotion assertion operator is missing"))?;
    let expected = assertion
        .get("expected")
        .cloned()
        .ok_or_else(|| anyhow!("regression promotion assertion expected value is missing"))?;
    let json_path_assertion = json_path_assertion_from_result(path, operator, expected)?;
    match target {
        "world_state" => Ok(ScenarioAssertion::WorldState {
            world_state: json_path_assertion,
        }),
        "frame_stats" => Ok(ScenarioAssertion::FrameStats {
            frame_stats: json_path_assertion,
        }),
        "runtime_events" => Ok(ScenarioAssertion::RuntimeEvents {
            runtime_events: json_path_assertion,
        }),
        "world_flags" => Ok(ScenarioAssertion::WorldFlags {
            world_flags: json_path_assertion,
        }),
        "physics_evidence" => Ok(ScenarioAssertion::PhysicsEvidence {
            physics_evidence: json_path_assertion,
        }),
        "performance_metrics" => Ok(ScenarioAssertion::PerformanceMetrics {
            performance_metrics: json_path_assertion,
        }),
        "console_errors" => Ok(ScenarioAssertion::ConsoleErrors {
            console_errors: json_path_assertion,
        }),
        "collision_evidence" => Ok(ScenarioAssertion::CollisionEvidence {
            collision_evidence: json_path_assertion,
        }),
        "audio_evidence" => Ok(ScenarioAssertion::AudioEvidence {
            audio_evidence: json_path_assertion,
        }),
        "animation_evidence" => Ok(ScenarioAssertion::AnimationEvidence {
            animation_evidence: json_path_assertion,
        }),
        "vfx_evidence" => Ok(ScenarioAssertion::VfxEvidence {
            vfx_evidence: json_path_assertion,
        }),
        "transition_evidence" => Ok(ScenarioAssertion::TransitionEvidence {
            transition_evidence: json_path_assertion,
        }),
        "scene3d_camera" => Ok(ScenarioAssertion::Scene3dCamera {
            scene3d_camera: json_path_assertion,
        }),
        "scene3d_animation" => Ok(ScenarioAssertion::Scene3dAnimation {
            scene3d_animation: json_path_assertion,
        }),
        "scene3d_probe" => Ok(ScenarioAssertion::Scene3dProbe {
            scene3d_probe: json_path_assertion,
        }),
        "scene3d_transform" => Ok(ScenarioAssertion::Scene3dTransform {
            scene3d_transform: json_path_assertion,
        }),
        "scene3d_render" => Ok(ScenarioAssertion::Scene3dRender {
            scene3d_render: json_path_assertion,
        }),
        "scene3d_collision" => Ok(ScenarioAssertion::Scene3dCollision {
            scene3d_collision: json_path_assertion,
        }),
        _ => Err(anyhow!(
            "regression promotion assertion target is unsupported: {target}"
        )),
    }
}
pub fn json_path_assertion_from_result(
    path: &str,
    operator: &str,
    expected: serde_json::Value,
) -> Result<JsonPathAssertion> {
    let mut assertion = JsonPathAssertion {
        path: path.to_string(),
        equals: None,
        not_equals: None,
        exists: None,
        contains: None,
        greater_than: None,
        less_than: None,
        count_equals: None,
        count_greater_than: None,
        count_less_than: None,
        contains_type: None,
    };
    match operator {
        "equals" => assertion.equals = Some(expected),
        "notEquals" => assertion.not_equals = Some(expected),
        "exists" => {
            assertion.exists = Some(expected.as_bool().ok_or_else(|| {
                anyhow!("regression promotion exists assertion expected value must be boolean")
            })?)
        }
        "contains" => assertion.contains = Some(expected),
        "greaterThan" => assertion.greater_than = Some(expected),
        "lessThan" => assertion.less_than = Some(expected),
        "countEquals" => {
            assertion.count_equals = Some(expected.as_u64().ok_or_else(|| {
                anyhow!("regression promotion countEquals expected value must be integer")
            })?)
        }
        "countGreaterThan" => {
            assertion.count_greater_than = Some(expected.as_u64().ok_or_else(|| {
                anyhow!("regression promotion countGreaterThan expected value must be integer")
            })?)
        }
        "countLessThan" => {
            assertion.count_less_than = Some(expected.as_u64().ok_or_else(|| {
                anyhow!("regression promotion countLessThan expected value must be integer")
            })?)
        }
        "containsType" => {
            assertion.contains_type = Some(
                expected
                    .as_str()
                    .ok_or_else(|| {
                        anyhow!("regression promotion containsType expected value must be a string")
                    })?
                    .to_string(),
            )
        }
        _ => {
            return Err(anyhow!(
                "regression promotion assertion operator is unsupported: {operator}"
            ))
        }
    }
    Ok(assertion)
}
pub fn regression_promotion_run_dir_ref(run_dir: &Path) -> Result<String> {
    let relative = if run_dir.is_absolute() {
        match std::env::current_dir()
            .ok()
            .and_then(|cwd| run_dir.strip_prefix(cwd).ok().map(Path::to_path_buf))
        {
            Some(path) => path,
            None => {
                let name = run_dir.file_name().ok_or_else(|| {
                    anyhow!("regression promotion run_dir has no final component")
                })?;
                Path::new("runs").join(name)
            }
        }
    } else {
        run_dir.to_path_buf()
    };
    let path = relative.to_string_lossy().to_string();
    validate_relative_artifact_path("regression promotion sourceRun runDir", &path)?;
    if !path.starts_with("runs/") {
        return Err(anyhow!(
            "regression promotion sourceRun runDir must point to runs/"
        ));
    }
    Ok(path)
}
