pub fn validate_safe_handoff_text(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    let lowered = value.to_ascii_lowercase();
    for forbidden in [
        "auto-apply",
        "auto-merge",
        "execute automatically",
        "grant authority",
        "mutate source code",
        "source-code mutation",
    ] {
        if lowered.contains(forbidden) {
            return Err(anyhow!("{field} contains unsafe action: {forbidden}"));
        }
    }
    Ok(())
}
pub fn validate_nonempty_text_list(field: &str, values: &[String]) -> Result<()> {
    if values.is_empty() {
        return Err(anyhow!("{field} must not be empty"));
    }
    for (index, value) in values.iter().enumerate() {
        require_text(&format!("{field}[{index}]"), value)?;
    }
    Ok(())
}
