impl GameplayBehaviorModelArtifact {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let artifact: GameplayBehaviorModelArtifact =
            serde_json::from_str(input).context("failed to parse Gameplay Behavior Model JSON")?;
        artifact.validate()?;
        Ok(artifact)
    }

    pub fn read_model_from_json_str(input: &str) -> Result<GameplayBehaviorModelReadModel> {
        let artifact = Self::from_json_str(input)?;
        Ok(artifact.read_model())
    }

    pub fn read_model(&self) -> GameplayBehaviorModelReadModel {
        let mut target_refs = BTreeSet::new();
        let mut trigger_kinds = BTreeSet::new();
        let mut condition_kinds = BTreeSet::new();
        let mut action_kinds = BTreeSet::new();
        let mut linked_evidence_refs = BTreeSet::new();
        let mut blocked_reasons = Vec::new();

        for reference in &self.evidence_refs {
            linked_evidence_refs.insert(reference.clone());
        }
        for reason in &self.blocked_reasons {
            blocked_reasons.push(reason.clone());
        }
        for behavior in &self.behaviors {
            for value in behavior.target.values() {
                target_refs.insert(value.clone());
            }
            collect_gameplay_behavior_step_kinds(&behavior.triggers, &mut trigger_kinds);
            collect_gameplay_behavior_step_kinds(&behavior.conditions, &mut condition_kinds);
            collect_gameplay_behavior_step_kinds(&behavior.actions, &mut action_kinds);
            for reference in &behavior.evidence_refs {
                linked_evidence_refs.insert(reference.clone());
            }
            for reason in &behavior.blocked_reasons {
                blocked_reasons.push(format!("{}: {reason}", behavior.id));
            }
        }

        GameplayBehaviorModelReadModel {
            schema_version: "gameplay-behavior-model-read-model.v1".to_string(),
            behavior_pack_id: self.behavior_pack_id.clone(),
            status: gameplay_behavior_status_label(self.status).to_string(),
            behavior_count: self.behaviors.len(),
            ready_count: self
                .behaviors
                .iter()
                .filter(|behavior| behavior.status == GameplayBehaviorStatus::Ready)
                .count(),
            partial_count: self
                .behaviors
                .iter()
                .filter(|behavior| behavior.status == GameplayBehaviorStatus::Partial)
                .count(),
            blocked_count: self
                .behaviors
                .iter()
                .filter(|behavior| behavior.status == GameplayBehaviorStatus::Blocked)
                .count(),
            unsupported_count: self
                .behaviors
                .iter()
                .filter(|behavior| behavior.status == GameplayBehaviorStatus::Unsupported)
                .count(),
            behavior_ids: self
                .behaviors
                .iter()
                .map(|behavior| behavior.id.clone())
                .collect(),
            target_refs: target_refs.into_iter().collect(),
            trigger_kinds: trigger_kinds.into_iter().collect(),
            condition_kinds: condition_kinds.into_iter().collect(),
            action_kinds: action_kinds.into_iter().collect(),
            linked_evidence_refs: linked_evidence_refs.into_iter().collect(),
            blocked_reasons,
            boundary: "Read-only Gameplay Behavior Model summary; no runtime execution, no script execution, no eval, no dynamic import, no plugin loader, no command bridge, no browser trusted writes, no source apply, and no production-stable scripting API claim.".to_string(),
        }
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != GAMEPLAY_BEHAVIOR_MODEL_SCHEMA_VERSION {
            return Err(anyhow!(
                "gameplay behavior model schemaVersion must be {GAMEPLAY_BEHAVIOR_MODEL_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("gameplay behavior behaviorPackId", &self.behavior_pack_id)?;
        validate_path_component("gameplay behavior scope", &self.scope)?;
        validate_gameplay_behavior_reason_state(
            "gameplay behavior model",
            self.status,
            &self.blocked_reasons,
        )?;
        validate_gameplay_behavior_refs(
            "gameplay behavior model evidenceRefs",
            &self.evidence_refs,
        )?;
        validate_gameplay_behavior_reasons(
            "gameplay behavior model blockedReasons",
            &self.blocked_reasons,
        )?;
        if self.behaviors.is_empty() {
            return Err(anyhow!(
                "gameplay behavior model behaviors must not be empty"
            ));
        }
        if self.behaviors.len() > MAX_GAMEPLAY_BEHAVIORS {
            return Err(anyhow!(
                "gameplay behavior model must contain at most {MAX_GAMEPLAY_BEHAVIORS} behaviors"
            ));
        }
        let mut ids = BTreeSet::new();
        for behavior in &self.behaviors {
            if !ids.insert(behavior.id.as_str()) {
                return Err(anyhow!("duplicate gameplay behavior id `{}`", behavior.id));
            }
            behavior.validate()?;
        }
        Ok(())
    }
}
impl GameplayBehaviorDefinition {
    pub fn validate(&self) -> Result<()> {
        validate_path_component("gameplay behavior id", &self.id)?;
        require_bounded_display_text("gameplay behavior label", &self.label)?;
        validate_gameplay_behavior_reason_state(
            "gameplay behavior",
            self.status,
            &self.blocked_reasons,
        )?;
        validate_gameplay_behavior_target(&self.id, &self.target)?;
        validate_gameplay_behavior_steps(
            &self.id,
            "triggers",
            &self.triggers,
            gameplay_trigger_kinds(),
        )?;
        validate_gameplay_behavior_steps(
            &self.id,
            "conditions",
            &self.conditions,
            gameplay_condition_kinds(),
        )?;
        validate_gameplay_behavior_steps(
            &self.id,
            "actions",
            &self.actions,
            gameplay_action_kinds(),
        )?;
        if matches!(self.status, GameplayBehaviorStatus::Ready) {
            if self.triggers.is_empty() {
                return Err(anyhow!(
                    "ready gameplay behavior `{}` must define at least one trigger",
                    self.id
                ));
            }
            if self.actions.is_empty() {
                return Err(anyhow!(
                    "ready gameplay behavior `{}` must define at least one action",
                    self.id
                ));
            }
        }
        validate_gameplay_behavior_variables(&self.id, &self.variables)?;
        validate_gameplay_behavior_cooldowns(&self.id, &self.cooldowns)?;
        validate_gameplay_behavior_timers(&self.id, &self.timers)?;
        validate_gameplay_behavior_refs("gameplay behavior evidenceRefs", &self.evidence_refs)?;
        validate_gameplay_behavior_reasons(
            "gameplay behavior blockedReasons",
            &self.blocked_reasons,
        )
    }
}
