impl GameplayEventSignalSystemArtifact {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let artifact: GameplayEventSignalSystemArtifact = serde_json::from_str(input)
            .context("failed to parse Gameplay Event Signal System JSON")?;
        artifact.validate()?;
        Ok(artifact)
    }

    pub fn queue_summary_from_json_str(input: &str) -> Result<GameplayEventSignalQueueSummary> {
        let artifact = Self::from_json_str(input)?;
        Ok(artifact.queue_summary())
    }

    pub fn read_model_from_json_str(input: &str) -> Result<GameplayEventSignalReadModel> {
        let artifact = Self::from_json_str(input)?;
        Ok(artifact.read_model())
    }

    pub fn read_model(&self) -> GameplayEventSignalReadModel {
        let mut event_type_counts = BTreeMap::new();
        let mut signal_names = BTreeSet::new();
        let mut source_refs = BTreeSet::new();
        let mut target_refs = BTreeSet::new();
        let mut linked_evidence_refs = BTreeSet::new();
        let mut blocked_reasons = Vec::new();

        for reference in &self.evidence_refs {
            linked_evidence_refs.insert(reference.clone());
        }
        for reason in &self.blocked_reasons {
            blocked_reasons.push(reason.clone());
        }
        for event in &self.events {
            *event_type_counts
                .entry(gameplay_event_signal_type_label(event.event_type).to_string())
                .or_insert(0) += 1;
            if let Some(signal_name) = &event.signal_name {
                signal_names.insert(signal_name.clone());
            }
            for value in event.source.values() {
                source_refs.insert(value.clone());
            }
            for value in event.target.values() {
                target_refs.insert(value.clone());
            }
            for reference in &event.evidence_refs {
                linked_evidence_refs.insert(reference.clone());
            }
            if let Some(reason) = &event.blocked_reason {
                blocked_reasons.push(format!("{}: {reason}", event.id));
            }
        }

        GameplayEventSignalReadModel {
            schema_version: "gameplay-event-signal-read-model.v1".to_string(),
            event_log_id: self.event_log_id.clone(),
            status: gameplay_event_signal_status_label(self.status).to_string(),
            event_count: self.events.len(),
            consumed_count: self.events.iter().filter(|event| event.consumed).count(),
            unconsumed_count: self.events.iter().filter(|event| !event.consumed).count(),
            event_type_counts,
            ordered_event_ids: self
                .ordered_events()
                .iter()
                .map(|event| event.id.clone())
                .collect(),
            signal_names: signal_names.into_iter().collect(),
            source_refs: source_refs.into_iter().collect(),
            target_refs: target_refs.into_iter().collect(),
            linked_evidence_refs: linked_evidence_refs.into_iter().collect(),
            blocked_reasons,
            queue_summary: self.queue_summary(),
            boundary: "Read-only Gameplay Event Signal evidence/read-model summary; no runtime execution, no script execution, no eval, no dynamic import, no plugin loader, no command bridge, no browser trusted writes, no source apply, and no production-stable scripting API claim.".to_string(),
        }
    }

    pub fn ordered_events(&self) -> Vec<&GameplayEventSignalDefinition> {
        let mut events: Vec<_> = self.events.iter().collect();
        events.sort_by(|left, right| {
            left.tick
                .cmp(&right.tick)
                .then(left.ordering_index.cmp(&right.ordering_index))
                .then(left.id.cmp(&right.id))
        });
        events
    }

    pub fn queue_summary(&self) -> GameplayEventSignalQueueSummary {
        let ordered_events = self.ordered_events();
        GameplayEventSignalQueueSummary {
            schema_version: "gameplay-event-signal-queue-summary.v1".to_string(),
            event_log_id: self.event_log_id.clone(),
            event_count: self.events.len(),
            consumed_count: self.events.iter().filter(|event| event.consumed).count(),
            unconsumed_count: self.events.iter().filter(|event| !event.consumed).count(),
            earliest_tick: ordered_events.first().map(|event| event.tick),
            latest_tick: ordered_events.last().map(|event| event.tick),
            ordered_event_ids: ordered_events
                .iter()
                .map(|event| event.id.clone())
                .collect(),
            queue_rules: vec![
                "Validate event artifacts before ordering.".to_string(),
                "Order events deterministically by tick, then orderingIndex, then id.".to_string(),
                "Keep consumed and unconsumed state visible; do not drop unconsumed events.".to_string(),
                format!("Bound queues to at most {MAX_GAMEPLAY_EVENTS} events for v1 fixtures."),
            ],
            boundary: "Read-only deterministic Gameplay Event Signal queue summary; no runtime execution, no script execution, no eval, no dynamic import, no plugin loader, no command bridge, no browser trusted writes, no source apply, and no production-stable scripting API claim.".to_string(),
        }
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != GAMEPLAY_EVENT_SIGNAL_SYSTEM_SCHEMA_VERSION {
            return Err(anyhow!(
                "gameplay event signal system schemaVersion must be {GAMEPLAY_EVENT_SIGNAL_SYSTEM_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("gameplay event signal eventLogId", &self.event_log_id)?;
        validate_path_component("gameplay event signal scope", &self.scope)?;
        validate_gameplay_event_signal_reason_state(
            "gameplay event signal system",
            self.status,
            &self.blocked_reasons,
        )?;
        validate_gameplay_behavior_refs(
            "gameplay event signal system evidenceRefs",
            &self.evidence_refs,
        )?;
        validate_gameplay_behavior_reasons(
            "gameplay event signal system blockedReasons",
            &self.blocked_reasons,
        )?;
        if self.events.is_empty() {
            return Err(anyhow!(
                "gameplay event signal system events must not be empty"
            ));
        }
        if self.events.len() > MAX_GAMEPLAY_EVENTS {
            return Err(anyhow!(
                "gameplay event signal system must contain at most {MAX_GAMEPLAY_EVENTS} events"
            ));
        }
        let mut ids = BTreeSet::new();
        for event in &self.events {
            if !ids.insert(event.id.as_str()) {
                return Err(anyhow!("duplicate gameplay event signal id `{}`", event.id));
            }
            event.validate()?;
        }
        Ok(())
    }
}
impl GameplayEventSignalDefinition {
    pub fn validate(&self) -> Result<()> {
        validate_path_component("gameplay event signal id", &self.id)?;
        if let Some(signal_name) = &self.signal_name {
            validate_path_component("gameplay event signal signalName", signal_name)?;
        }
        validate_gameplay_event_signal_party(&self.id, "source", &self.source)?;
        validate_gameplay_event_signal_party(&self.id, "target", &self.target)?;
        validate_gameplay_event_signal_payload(&self.id, &self.payload)?;
        if self.tick > 9_999_999_999 {
            return Err(anyhow!(
                "gameplay event signal `{}` tick must be bounded",
                self.id
            ));
        }
        if self.timestamp_unix_ms == Some(0) {
            return Err(anyhow!(
                "gameplay event signal `{}` timestampUnixMs must be non-zero when present",
                self.id
            ));
        }
        if self.ordering_index > MAX_GAMEPLAY_EVENTS as u32 {
            return Err(anyhow!(
                "gameplay event signal `{}` orderingIndex must be bounded",
                self.id
            ));
        }
        if !self.consumed && !self.consumed_by.is_empty() {
            return Err(anyhow!(
                "unconsumed gameplay event signal `{}` must not list consumedBy",
                self.id
            ));
        }
        if self.consumed && self.consumed_by.is_empty() {
            return Err(anyhow!(
                "consumed gameplay event signal `{}` must list at least one consumer in consumedBy",
                self.id
            ));
        }
        if self.consumed_by.len() > MAX_GAMEPLAY_EVENT_PARTIES {
            return Err(anyhow!(
                "gameplay event signal `{}` consumedBy must be bounded",
                self.id
            ));
        }
        for consumer in &self.consumed_by {
            validate_path_component("gameplay event signal consumedBy", consumer)?;
        }
        if let Some(reason) = &self.blocked_reason {
            require_bounded_display_text("gameplay event signal blockedReason", reason)?;
        }
        validate_gameplay_behavior_refs("gameplay event signal evidenceRefs", &self.evidence_refs)
    }
}
