impl GameplayAbilityActionArtifact {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let artifact: GameplayAbilityActionArtifact =
            serde_json::from_str(input).context("failed to parse Gameplay Ability Action JSON")?;
        artifact.validate()?;
        Ok(artifact)
    }

    pub fn read_model_from_json_str(input: &str) -> Result<GameplayAbilityActionReadModel> {
        let artifact = Self::from_json_str(input)?;
        Ok(artifact.read_model())
    }

    pub fn read_model(&self) -> GameplayAbilityActionReadModel {
        let mut runtime_status_counts = BTreeMap::new();
        let mut target_refs = BTreeSet::new();
        let mut trigger_kinds = BTreeSet::new();
        let mut effect_kinds = BTreeSet::new();
        let mut cost_kinds = BTreeSet::new();
        let mut linked_evidence_refs = BTreeSet::new();
        let mut blocked_reasons = Vec::new();

        for reference in &self.evidence_refs {
            linked_evidence_refs.insert(reference.clone());
        }
        for reason in &self.blocked_reasons {
            blocked_reasons.push(reason.clone());
        }
        for ability in &self.abilities {
            *runtime_status_counts
                .entry(gameplay_ability_runtime_status_label(ability.runtime_status).to_string())
                .or_insert(0) += 1;
            for value in ability.target.values() {
                target_refs.insert(value.clone());
            }
            collect_gameplay_ability_step_kind(&ability.trigger, &mut trigger_kinds);
            collect_gameplay_ability_step_kind(&ability.effect, &mut effect_kinds);
            for cost in &ability.costs {
                cost_kinds.insert(cost.kind.clone());
            }
            for reference in &ability.evidence_refs {
                linked_evidence_refs.insert(reference.clone());
            }
            for reason in &ability.blocked_reasons {
                blocked_reasons.push(format!("{}: {reason}", ability.id));
            }
        }

        GameplayAbilityActionReadModel {
            schema_version: "gameplay-ability-action-read-model.v1".to_string(),
            ability_pack_id: self.ability_pack_id.clone(),
            status: gameplay_ability_action_status_label(self.status).to_string(),
            ability_count: self.abilities.len(),
            ready_count: self
                .abilities
                .iter()
                .filter(|ability| ability.status == GameplayAbilityActionStatus::Ready)
                .count(),
            partial_count: self
                .abilities
                .iter()
                .filter(|ability| ability.status == GameplayAbilityActionStatus::Partial)
                .count(),
            blocked_count: self
                .abilities
                .iter()
                .filter(|ability| ability.status == GameplayAbilityActionStatus::Blocked)
                .count(),
            unsupported_count: self
                .abilities
                .iter()
                .filter(|ability| ability.status == GameplayAbilityActionStatus::Unsupported)
                .count(),
            ability_ids: self
                .abilities
                .iter()
                .map(|ability| ability.id.clone())
                .collect(),
            action_ids: self
                .abilities
                .iter()
                .map(|ability| ability.action_id.clone())
                .collect(),
            runtime_status_counts,
            target_refs: target_refs.into_iter().collect(),
            trigger_kinds: trigger_kinds.into_iter().collect(),
            effect_kinds: effect_kinds.into_iter().collect(),
            cost_kinds: cost_kinds.into_iter().collect(),
            linked_evidence_refs: linked_evidence_refs.into_iter().collect(),
            blocked_reasons,
            boundary: "Read-only Gameplay Ability Action evidence/read-model summary; no runtime execution, no script execution, no eval, no dynamic import, no plugin loader, no command bridge, no browser trusted writes, no source apply, and no production-stable scripting API claim.".to_string(),
        }
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != GAMEPLAY_ABILITY_ACTION_SCHEMA_VERSION {
            return Err(anyhow!(
                "gameplay ability action schemaVersion must be {GAMEPLAY_ABILITY_ACTION_SCHEMA_VERSION}"
            ));
        }
        validate_path_component(
            "gameplay ability action abilityPackId",
            &self.ability_pack_id,
        )?;
        validate_path_component("gameplay ability action scope", &self.scope)?;
        validate_gameplay_ability_reason_state(
            "gameplay ability action pack",
            self.status,
            &self.blocked_reasons,
        )?;
        validate_gameplay_behavior_refs(
            "gameplay ability action evidenceRefs",
            &self.evidence_refs,
        )?;
        validate_gameplay_behavior_reasons(
            "gameplay ability action blockedReasons",
            &self.blocked_reasons,
        )?;
        if self.abilities.is_empty() {
            return Err(anyhow!(
                "gameplay ability action abilities must not be empty"
            ));
        }
        if self.abilities.len() > MAX_GAMEPLAY_ABILITIES {
            return Err(anyhow!(
                "gameplay ability action pack must contain at most {MAX_GAMEPLAY_ABILITIES} abilities"
            ));
        }
        let mut ids = BTreeSet::new();
        let mut action_ids = BTreeSet::new();
        for ability in &self.abilities {
            if !ids.insert(ability.id.as_str()) {
                return Err(anyhow!("duplicate gameplay ability id `{}`", ability.id));
            }
            if !action_ids.insert(ability.action_id.as_str()) {
                return Err(anyhow!(
                    "duplicate gameplay ability actionId `{}`",
                    ability.action_id
                ));
            }
            ability.validate()?;
        }
        Ok(())
    }
}
impl GameplayAbilityDefinition {
    pub fn validate(&self) -> Result<()> {
        validate_path_component("gameplay ability id", &self.id)?;
        validate_path_component("gameplay ability actionId", &self.action_id)?;
        require_bounded_display_text("gameplay ability label", &self.label)?;
        validate_gameplay_ability_reason_state(
            "gameplay ability",
            self.status,
            &self.blocked_reasons,
        )?;
        validate_gameplay_ability_runtime_state(
            &self.id,
            self.status,
            self.runtime_status,
            &self.blocked_reasons,
        )?;
        validate_gameplay_ability_target(&self.id, &self.target)?;
        validate_gameplay_ability_step(
            &self.id,
            "trigger",
            &self.trigger,
            gameplay_ability_trigger_kinds(),
        )?;
        if let Some(cooldown) = &self.cooldown {
            cooldown.validate(&self.id)?;
        }
        validate_gameplay_ability_costs(&self.id, &self.costs)?;
        if let Some(duration_ms) = self.duration_ms {
            validate_gameplay_ability_duration(&self.id, "durationMs", duration_ms)?;
        }
        validate_gameplay_ability_step(
            &self.id,
            "effect",
            &self.effect,
            gameplay_ability_effect_kinds(),
        )?;
        validate_gameplay_behavior_refs("gameplay ability evidenceRefs", &self.evidence_refs)?;
        validate_gameplay_behavior_reasons("gameplay ability blockedReasons", &self.blocked_reasons)
    }
}
impl GameplayAbilityCooldown {
    pub fn validate(&self, ability_id: &str) -> Result<()> {
        validate_path_component("gameplay ability cooldown id", &self.id)?;
        validate_gameplay_ability_duration(ability_id, "cooldown.durationMs", self.duration_ms)?;
        if let Some(remaining_ms) = self.remaining_ms {
            if remaining_ms > self.duration_ms {
                return Err(anyhow!(
                    "gameplay ability `{ability_id}` cooldown remainingMs must not exceed durationMs"
                ));
            }
        }
        Ok(())
    }
}
pub fn gameplay_ability_action_status_label(status: GameplayAbilityActionStatus) -> &'static str {
    match status {
        GameplayAbilityActionStatus::Ready => "ready",
        GameplayAbilityActionStatus::Partial => "partial",
        GameplayAbilityActionStatus::Blocked => "blocked",
        GameplayAbilityActionStatus::Unsupported => "unsupported",
    }
}
pub fn gameplay_ability_runtime_status_label(status: GameplayAbilityRuntimeStatus) -> &'static str {
    match status {
        GameplayAbilityRuntimeStatus::Available => "available",
        GameplayAbilityRuntimeStatus::Active => "active",
        GameplayAbilityRuntimeStatus::OnCooldown => "on_cooldown",
        GameplayAbilityRuntimeStatus::InsufficientCost => "insufficient_cost",
        GameplayAbilityRuntimeStatus::Blocked => "blocked",
        GameplayAbilityRuntimeStatus::Unsupported => "unsupported",
    }
}
pub fn collect_gameplay_ability_step_kind(
    step: &BTreeMap<String, serde_json::Value>,
    output: &mut BTreeSet<String>,
) {
    if let Some(kind) = step.get("kind").and_then(|value| value.as_str()) {
        output.insert(kind.to_string());
    }
}
pub fn gameplay_ability_trigger_kinds() -> BTreeSet<&'static str> {
    BTreeSet::from([
        "on_input",
        "on_event",
        "on_signal",
        "on_state_entered",
        "on_timer",
        "on_contact",
        "on_collect",
    ])
}
pub fn gameplay_ability_effect_kinds() -> BTreeSet<&'static str> {
    BTreeSet::from([
        "movement_impulse",
        "set_state",
        "emit_signal",
        "set_flag",
        "damage",
        "heal",
        "open_door",
        "complete_objective",
        "spawn_local_effect",
        "play_animation",
    ])
}
pub fn gameplay_ability_cost_kinds() -> BTreeSet<&'static str> {
    BTreeSet::from(["stamina", "mana", "ammo", "item", "charge", "counter"])
}
pub fn validate_gameplay_ability_reason_state(
    field: &str,
    status: GameplayAbilityActionStatus,
    reasons: &[String],
) -> Result<()> {
    if matches!(
        status,
        GameplayAbilityActionStatus::Blocked | GameplayAbilityActionStatus::Unsupported
    ) && reasons.is_empty()
    {
        return Err(anyhow!(
            "{field} with blocked or unsupported status must include blockedReasons"
        ));
    }
    Ok(())
}
pub fn validate_gameplay_ability_runtime_state(
    ability_id: &str,
    status: GameplayAbilityActionStatus,
    runtime_status: GameplayAbilityRuntimeStatus,
    blocked_reasons: &[String],
) -> Result<()> {
    if matches!(
        runtime_status,
        GameplayAbilityRuntimeStatus::Blocked | GameplayAbilityRuntimeStatus::Unsupported
    ) && blocked_reasons.is_empty()
    {
        return Err(anyhow!(
            "gameplay ability `{ability_id}` blocked or unsupported runtimeStatus requires blockedReasons"
        ));
    }
    if matches!(status, GameplayAbilityActionStatus::Ready)
        && matches!(
            runtime_status,
            GameplayAbilityRuntimeStatus::Blocked | GameplayAbilityRuntimeStatus::Unsupported
        )
    {
        return Err(anyhow!(
            "ready gameplay ability `{ability_id}` must not use blocked or unsupported runtimeStatus"
        ));
    }
    Ok(())
}
pub fn validate_gameplay_ability_target(
    ability_id: &str,
    target: &BTreeMap<String, String>,
) -> Result<()> {
    if target.is_empty() {
        return Err(anyhow!(
            "gameplay ability `{ability_id}` target must not be empty"
        ));
    }
    for (key, value) in target {
        require_supported_gameplay_ability_key("target", key)?;
        if key.ends_with("Ref") {
            validate_repo_relative_source_ref("gameplay ability target ref", value)?;
        } else {
            validate_path_component("gameplay ability target", value)?;
        }
    }
    Ok(())
}
pub fn validate_gameplay_ability_step(
    ability_id: &str,
    field: &str,
    step: &BTreeMap<String, serde_json::Value>,
    supported_kinds: BTreeSet<&str>,
) -> Result<()> {
    let Some(kind) = step.get("kind").and_then(|value| value.as_str()) else {
        return Err(anyhow!(
            "gameplay ability `{ability_id}` {field} requires string kind"
        ));
    };
    if !supported_kinds.contains(kind) {
        return Err(anyhow!(
            "gameplay ability `{ability_id}` {field} contains unsupported kind `{kind}`"
        ));
    }
    if step.len() > MAX_GAMEPLAY_ABILITY_STEPS {
        return Err(anyhow!(
            "gameplay ability `{ability_id}` {field} payload must be bounded"
        ));
    }
    validate_path_component("gameplay ability step kind", kind)?;
    for (key, value) in step {
        require_supported_gameplay_ability_key(field, key)?;
        validate_gameplay_behavior_value(
            &format!("gameplay ability `{ability_id}` {field}.{key}"),
            value,
        )?;
    }
    Ok(())
}
pub fn validate_gameplay_ability_costs(
    ability_id: &str,
    costs: &[GameplayAbilityCost],
) -> Result<()> {
    if costs.len() > MAX_GAMEPLAY_ABILITY_STEPS {
        return Err(anyhow!(
            "gameplay ability `{ability_id}` costs must be bounded"
        ));
    }
    let mut ids = BTreeSet::new();
    let supported = gameplay_ability_cost_kinds();
    for cost in costs {
        validate_path_component("gameplay ability cost kind", &cost.kind)?;
        if !supported.contains(cost.kind.as_str()) {
            return Err(anyhow!(
                "gameplay ability `{ability_id}` costs contains unsupported kind `{}`",
                cost.kind
            ));
        }
        if let Some(resource_id) = &cost.resource_id {
            validate_path_component("gameplay ability cost resourceId", resource_id)?;
        }
        let key = format!(
            "{}:{}",
            cost.kind,
            cost.resource_id.as_deref().unwrap_or("")
        );
        if !ids.insert(key) {
            return Err(anyhow!(
                "duplicate cost `{}` in gameplay ability `{ability_id}`",
                cost.kind
            ));
        }
        if cost.amount == 0 || cost.amount > MAX_GAMEPLAY_ABILITY_COST {
            return Err(anyhow!(
                "gameplay ability `{ability_id}` cost amount must be between 1 and {MAX_GAMEPLAY_ABILITY_COST}"
            ));
        }
    }
    Ok(())
}
pub fn validate_gameplay_ability_duration(
    ability_id: &str,
    field: &str,
    duration_ms: u64,
) -> Result<()> {
    if duration_ms == 0 || duration_ms > MAX_GAMEPLAY_ABILITY_DURATION_MS {
        return Err(anyhow!(
            "gameplay ability `{ability_id}` {field} must be between 1 and {MAX_GAMEPLAY_ABILITY_DURATION_MS}"
        ));
    }
    Ok(())
}
pub fn require_supported_gameplay_ability_key(field: &str, key: &str) -> Result<()> {
    validate_path_component("gameplay ability field key", key)?;
    let normalized: String = key
        .chars()
        .filter(|c| c.is_ascii_alphanumeric())
        .map(|c| c.to_ascii_lowercase())
        .collect();
    let forbidden = [
        "script",
        "command",
        "commandbridge",
        "trustedwrite",
        "dynamicimport",
        "pluginloader",
        "eval",
    ];
    if forbidden.iter().any(|blocked| normalized.contains(blocked)) {
        return Err(anyhow!("gameplay ability {field} key `{key}` is forbidden because #614 does not authorize scripts, command bridges, plugin loading, or trusted browser writes"));
    }
    Ok(())
}
