pub fn qa_worker_output_roots_overlap(left: &str, right: &str) -> bool {
    let normalize = |value: &str| {
        if value.ends_with('/') {
            value.to_string()
        } else {
            format!("{value}/")
        }
    };
    let left = normalize(left);
    let right = normalize(right);
    left.starts_with(&right) || right.starts_with(&left)
}
