impl SourcePatchTestCommandAllowlist {
    pub fn match_command(
        &self,
        command: &SourcePatchTestCommand,
    ) -> Option<SourcePatchTestCommandMatch> {
        if classify_source_patch_forbidden_test_command(command).is_some() {
            return None;
        }
        let normalized_argv = command
            .argv
            .iter()
            .map(|arg| arg.trim().to_string())
            .collect::<Vec<_>>();
        self.policies.iter().find_map(|policy| {
            let matched = match policy.match_kind {
                SourcePatchTestCommandMatchKind::Exact => normalized_argv == policy.argv,
                SourcePatchTestCommandMatchKind::Prefix => {
                    argv_matches_policy_prefix(normalized_argv.as_slice(), policy.argv.as_slice())
                }
            };
            matched.then(|| SourcePatchTestCommandMatch {
                policy_id: policy.policy_id.clone(),
                kind: policy.match_kind.clone(),
                normalized_argv: normalized_argv.clone(),
                boundary: policy.boundary.clone(),
            })
        })
    }
}
pub fn classify_source_patch_forbidden_test_command(
    command: &SourcePatchTestCommand,
) -> Option<SourcePatchForbiddenTestCommandReport> {
    classify_forbidden_source_patch_test_argv(&command.argv)
}
pub fn classify_forbidden_source_patch_test_argv(
    argv: &[String],
) -> Option<SourcePatchForbiddenTestCommandReport> {
    let normalized = argv
        .iter()
        .map(|arg| arg.trim().to_ascii_lowercase())
        .collect::<Vec<_>>();
    let program = normalized.first().map(String::as_str).unwrap_or("");
    let joined = normalized.join(" ");

    if argv.iter().any(|arg| contains_shell_metacharacter(arg))
        || matches!(
            program,
            "bash" | "sh" | "zsh" | "fish" | "pwsh" | "powershell"
        )
        || normalized.iter().any(|arg| arg == "-c")
    {
        return Some(forbidden_source_patch_test_command_report(
            SourcePatchForbiddenTestCommandKind::ShellExecution,
            "arbitrary shell execution or shell metacharacter composition is not allowed",
        ));
    }
    if matches!(
        program,
        "curl" | "wget" | "ssh" | "scp" | "rsync" | "nc" | "netcat" | "ftp" | "sftp"
    ) || joined.contains("http://")
        || joined.contains("https://")
    {
        return Some(forbidden_source_patch_test_command_report(
            SourcePatchForbiddenTestCommandKind::NetworkAccess,
            "network, remote service, or hosted API commands are not allowed",
        ));
    }
    if (program == "npm"
        && normalized
            .get(1)
            .is_some_and(|arg| arg == "install" || arg == "i"))
        || (program == "pnpm" && normalized.get(1).is_some_and(|arg| arg == "install"))
        || (program == "yarn" && normalized.get(1).is_some_and(|arg| arg == "install"))
        || (program == "cargo" && normalized.get(1).is_some_and(|arg| arg == "install"))
        || (program == "pip" && normalized.get(1).is_some_and(|arg| arg == "install"))
        || matches!(program, "brew" | "curl-bash")
    {
        return Some(forbidden_source_patch_test_command_report(
            SourcePatchForbiddenTestCommandKind::InstallOrBootstrap,
            "install, bootstrap, or package acquisition commands are not allowed",
        ));
    }
    if program == "cargo" {
        if let Some(reason) = cargo_source_patch_test_workspace_escape_reason(argv, &normalized) {
            return Some(forbidden_source_patch_test_command_report(
                SourcePatchForbiddenTestCommandKind::WorkspaceEscape,
                &reason,
            ));
        }
    }

    if (program == "cargo"
        && normalized
            .get(1)
            .is_some_and(|arg| arg == "add" || arg == "update"))
        || (program == "npm"
            && normalized.get(1).is_some_and(|arg| {
                matches!(
                    arg.as_str(),
                    "update" | "upgrade" | "add" | "audit" | "dedupe"
                )
            }))
        || (program == "pnpm"
            && normalized
                .get(1)
                .is_some_and(|arg| matches!(arg.as_str(), "update" | "upgrade" | "add")))
        || (program == "yarn"
            && normalized
                .get(1)
                .is_some_and(|arg| matches!(arg.as_str(), "upgrade" | "add")))
    {
        return Some(forbidden_source_patch_test_command_report(
            SourcePatchForbiddenTestCommandKind::DependencyMutation,
            "dependency mutation commands are not allowed",
        ));
    }
    if (program == "gh" && normalized.iter().any(|arg| arg == "auth"))
        || matches!(program, "aws" | "gcloud" | "az" | "op" | "security")
        || normalized.iter().any(|arg| {
            matches!(
                arg.as_str(),
                "token" | "secret" | "credential" | "credentials"
            )
        })
    {
        return Some(forbidden_source_patch_test_command_report(
            SourcePatchForbiddenTestCommandKind::CredentialAccess,
            "credential, token, or cloud-auth commands are not allowed",
        ));
    }
    if (program == "rm"
        && normalized
            .iter()
            .any(|arg| arg.contains('r') || arg == "-rf"))
        || (program == "git"
            && normalized
                .get(1)
                .is_some_and(|arg| matches!(arg.as_str(), "clean" | "reset" | "checkout")))
        || matches!(program, "trash" | "unlink")
    {
        return Some(forbidden_source_patch_test_command_report(
            SourcePatchForbiddenTestCommandKind::DestructiveFilesystem,
            "destructive filesystem or worktree reset commands are not allowed",
        ));
    }
    if (program == "git"
        && normalized.get(1).is_some_and(|arg| {
            matches!(
                arg.as_str(),
                "apply" | "am" | "merge" | "rebase" | "cherry-pick" | "push"
            )
        }))
        || joined.contains("auto-merge")
        || joined.contains("auto-apply")
    {
        return Some(forbidden_source_patch_test_command_report(
            SourcePatchForbiddenTestCommandKind::SourceApplyOrMerge,
            "source patch apply, merge, rebase, push, or auto-apply commands are not allowed",
        ));
    }
    None
}
pub fn cargo_source_patch_test_workspace_escape_reason(
    raw_argv: &[String],
    normalized_argv: &[String],
) -> Option<String> {
    const BLOCKED_FLAGS: [&str; 3] = ["--manifest-path", "--config", "--target-dir"];
    for arg in normalized_argv.iter().skip(1) {
        if BLOCKED_FLAGS
            .iter()
            .any(|flag| arg == flag || arg.starts_with(&format!("{flag}=")))
        {
            return Some(format!(
                "cargo sandbox tests may not override workspace, manifest, config, or target-dir with `{arg}`"
            ));
        }
    }
    for arg in raw_argv.iter().skip(1) {
        if source_patch_test_arg_has_sandbox_escaping_path(arg) {
            return Some(format!(
                "cargo sandbox tests may not use absolute or parent-relative path argument `{}`",
                arg.trim()
            ));
        }
    }
    None
}
pub fn source_patch_test_arg_has_sandbox_escaping_path(arg: &str) -> bool {
    let trimmed = arg.trim();
    if trimmed.is_empty() || trimmed == "--" {
        return false;
    }
    let path_candidate = trimmed
        .strip_prefix("--")
        .and_then(|flag| flag.split_once('=').map(|(_, value)| value))
        .unwrap_or(trimmed);
    if path_candidate.is_empty() {
        return false;
    }
    let path = Path::new(path_candidate);
    path.is_absolute()
        || path
            .components()
            .any(|component| matches!(component, Component::ParentDir))
}
pub fn forbidden_source_patch_test_command_report(
    kind: SourcePatchForbiddenTestCommandKind,
    reason: &str,
) -> SourcePatchForbiddenTestCommandReport {
    SourcePatchForbiddenTestCommandReport {
        kind,
        reason: reason.to_string(),
        boundary: "source patch command policy rejects before sandbox execution; no command is run"
            .to_string(),
    }
}
pub fn contains_shell_metacharacter(arg: &str) -> bool {
    ["&&", "||", "$(", "`", ";", "|", ">", "<"]
        .iter()
        .any(|needle| arg.contains(needle))
}
pub fn argv_matches_policy_prefix(argv: &[String], policy_prefix: &[String]) -> bool {
    if argv.len() < policy_prefix.len() {
        return false;
    }
    policy_prefix.iter().enumerate().all(|(index, expected)| {
        let actual = &argv[index];
        if expected.ends_with('/') {
            actual.starts_with(expected)
        } else {
            actual == expected
        }
    })
}
pub fn default_source_patch_test_command_allowlist() -> SourcePatchTestCommandAllowlist {
    let boundary = "inert source patch test command allowlist; does not execute commands";
    SourcePatchTestCommandAllowlist {
        boundary: boundary.to_string(),
        policies: vec![
            SourcePatchTestCommandPolicy {
                policy_id: "cargo-fmt-check".to_string(),
                match_kind: SourcePatchTestCommandMatchKind::Exact,
                argv: vec!["cargo", "fmt", "--check"]
                    .into_iter()
                    .map(str::to_string)
                    .collect(),
                boundary: boundary.to_string(),
            },
            SourcePatchTestCommandPolicy {
                policy_id: "cargo-clippy-all-targets-all-features-deny-warnings".to_string(),
                match_kind: SourcePatchTestCommandMatchKind::Exact,
                argv: vec![
                    "cargo",
                    "clippy",
                    "--all-targets",
                    "--all-features",
                    "--",
                    "-D",
                    "warnings",
                ]
                .into_iter()
                .map(str::to_string)
                .collect(),
                boundary: boundary.to_string(),
            },
            SourcePatchTestCommandPolicy {
                policy_id: "cargo-test-ouroforge-core-focused".to_string(),
                match_kind: SourcePatchTestCommandMatchKind::Prefix,
                argv: vec!["cargo", "test", "-p", "ouroforge-core"]
                    .into_iter()
                    .map(str::to_string)
                    .collect(),
                boundary: boundary.to_string(),
            },
            SourcePatchTestCommandPolicy {
                policy_id: "cargo-test-ouroforge-cli-focused".to_string(),
                match_kind: SourcePatchTestCommandMatchKind::Prefix,
                argv: vec!["cargo", "test", "-p", "ouroforge-cli"]
                    .into_iter()
                    .map(str::to_string)
                    .collect(),
                boundary: boundary.to_string(),
            },
            SourcePatchTestCommandPolicy {
                policy_id: "node-check-known-examples".to_string(),
                match_kind: SourcePatchTestCommandMatchKind::Prefix,
                argv: vec!["node", "--check", "examples/"]
                    .into_iter()
                    .map(str::to_string)
                    .collect(),
                boundary: boundary.to_string(),
            },
            SourcePatchTestCommandPolicy {
                policy_id: "node-test-known-examples".to_string(),
                match_kind: SourcePatchTestCommandMatchKind::Prefix,
                argv: vec!["node", "examples/"]
                    .into_iter()
                    .map(str::to_string)
                    .collect(),
                boundary: boundary.to_string(),
            },
        ],
    }
}
