pub fn validate_visual_edit_draft_hash(field: &str, value: &str) -> Result<()> {
    parse_visual_edit_draft_hash(field, value)?;
    Ok(())
}
pub fn parse_visual_edit_draft_hash(field: &str, value: &str) -> Result<(String, String)> {
    require_text(field, value)?;
    if let Some(hash) = value.strip_prefix("sha256:") {
        if hash.len() == 64
            && hash
                .chars()
                .all(|ch| ch.is_ascii_digit() || matches!(ch, 'a'..='f'))
        {
            return Ok(("sha256".to_string(), hash.to_string()));
        }
        return Err(anyhow!("{field} must use sha256:<64 lowercase hex>"));
    }
    if let Some(hash) = value.strip_prefix("fnv1a64-canonical-json-v1:") {
        if hash.len() == 16
            && hash
                .chars()
                .all(|ch| ch.is_ascii_digit() || matches!(ch, 'a'..='f'))
        {
            return Ok(("fnv1a64-canonical-json-v1".to_string(), hash.to_string()));
        }
        return Err(anyhow!(
            "{field} must use fnv1a64-canonical-json-v1:<16 lowercase hex>"
        ));
    }
    if let Some(hash) = value.strip_prefix("fnv1a64-file-v1:") {
        if hash.len() == 16
            && hash
                .chars()
                .all(|ch| ch.is_ascii_digit() || matches!(ch, 'a'..='f'))
        {
            return Ok(("fnv1a64-file-v1".to_string(), hash.to_string()));
        }
        return Err(anyhow!(
            "{field} must use fnv1a64-file-v1:<16 lowercase hex>"
        ));
    }
    Err(anyhow!(
        "{field} must use sha256:<64 lowercase hex>, fnv1a64-canonical-json-v1:<16 lowercase hex>, or fnv1a64-file-v1:<16 lowercase hex>"
    ))
}
pub fn validate_visual_edit_draft_operation_path(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    if !value.chars().all(|ch| {
        ch.is_ascii_alphanumeric() || matches!(ch, '.' | '-' | '_' | '[' | ']' | ',' | '/')
    }) {
        return Err(anyhow!(
            "{field} may only contain ASCII letters, numbers, '.', '-', '_', '[', ']', ',' or '/'"
        ));
    }
    if value.contains("..") || value.starts_with('/') || value.starts_with('.') {
        return Err(anyhow!(
            "{field} must stay inside the target draft address space"
        ));
    }
    Ok(())
}
