impl PatchSandboxPlan {
    pub fn validate(&self, run_dir: impl AsRef<Path>) -> Result<()> {
        if self.schema_version != "1" {
            return Err(anyhow!("patch sandbox schema_version must be \"1\""));
        }
        require_text("patch sandbox run_id", &self.run_id)?;
        self.layout.validate(run_dir)?;
        if self.verification_commands.is_empty() {
            return Err(anyhow!(
                "patch sandbox plan requires at least one verification command"
            ));
        }
        for command in &self.verification_commands {
            require_text("patch sandbox verification command", command)?;
        }
        Ok(())
    }
}
impl PatchSandboxLayout {
    pub fn validate(&self, run_dir: impl AsRef<Path>) -> Result<()> {
        require_text("patch sandbox sandbox_id", &self.sandbox_id)?;
        validate_sandbox_id(&self.sandbox_id)?;
        require_text("patch sandbox patch_draft_id", &self.patch_draft_id)?;
        let expected_root = format!("sandbox/{}", self.sandbox_id);
        let expected_worktree = format!("{expected_root}/worktree");
        let expected_evidence = format!("{expected_root}/evidence");
        let expected_plan = format!("{expected_root}/plan.json");
        if self.sandbox_root != expected_root {
            return Err(anyhow!("patch sandbox root does not match sandbox id"));
        }
        if self.worktree_path != expected_worktree {
            return Err(anyhow!("patch sandbox worktree path is invalid"));
        }
        if self.evidence_path != expected_evidence {
            return Err(anyhow!("patch sandbox evidence path is invalid"));
        }
        if self.plan_path != expected_plan {
            return Err(anyhow!("patch sandbox plan path is invalid"));
        }
        for relative in [
            &self.sandbox_root,
            &self.worktree_path,
            &self.evidence_path,
            &self.plan_path,
        ] {
            validate_run_relative_sandbox_path(relative)?;
            ensure_path_inside(run_dir.as_ref(), &run_dir.as_ref().join(relative))?;
        }
        Ok(())
    }
}
pub fn validate_sandbox_id(sandbox_id: &str) -> Result<()> {
    require_text("patch sandbox sandbox_id", sandbox_id)?;
    if !sandbox_id
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || ch == '-')
    {
        return Err(anyhow!(
            "patch sandbox sandbox_id may contain only ASCII letters, digits, and '-'"
        ));
    }
    Ok(())
}
pub fn validate_run_relative_sandbox_path(relative_path: &str) -> Result<()> {
    require_text("patch sandbox path", relative_path)?;
    let path = Path::new(relative_path);
    if path.is_absolute() {
        return Err(anyhow!("patch sandbox path must be relative"));
    }
    let mut components = path.components();
    if components.next() != Some(Component::Normal(std::ffi::OsStr::new("sandbox"))) {
        return Err(anyhow!("patch sandbox path must stay under sandbox/"));
    }
    if path.components().any(|component| {
        matches!(
            component,
            Component::ParentDir | Component::RootDir | Component::Prefix(_)
        )
    }) {
        return Err(anyhow!("patch sandbox path must not escape the run"));
    }
    Ok(())
}
pub fn ensure_path_inside(root: &Path, candidate: &Path) -> Result<()> {
    let root = root
        .canonicalize()
        .with_context(|| format!("failed to canonicalize root {}", root.display()))?;
    // If the candidate already exists, canonicalize it directly so a symlinked
    // leaf that resolves outside the root is rejected (canonicalizing only the
    // parent would miss a worktree symlink that escapes the sandbox).
    if candidate.exists() {
        let canonical = candidate
            .canonicalize()
            .with_context(|| format!("failed to canonicalize {}", candidate.display()))?;
        if !canonical.starts_with(&root) {
            return Err(anyhow!("path is outside sandbox root"));
        }
        return Ok(());
    }
    let parent = candidate.parent().unwrap_or(candidate);
    let existing_parent = first_existing_ancestor(parent)
        .ok_or_else(|| anyhow!("no existing parent for {}", candidate.display()))?;
    let canonical_parent = existing_parent
        .canonicalize()
        .with_context(|| format!("failed to canonicalize {}", existing_parent.display()))?;
    if !canonical_parent.starts_with(&root) {
        return Err(anyhow!("path is outside sandbox root"));
    }
    Ok(())
}
pub fn first_existing_ancestor(path: &Path) -> Option<&Path> {
    let mut current = Some(path);
    while let Some(candidate) = current {
        if candidate.exists() {
            return Some(candidate);
        }
        current = candidate.parent();
    }
    None
}
pub fn plan_patch_sandbox(
    run_dir: impl AsRef<Path>,
    patch_draft_id: &str,
) -> Result<PatchSandboxPlan> {
    let run_dir = run_dir.as_ref();
    require_text("patch sandbox patch_draft_id", patch_draft_id)?;
    validate_sandbox_id(patch_draft_id)?;
    let run = read_json_value(run_dir.join("run.json"))?;
    let run_id = json_string(&run, "id").unwrap_or_else(|| {
        run_dir
            .file_name()
            .and_then(|name| name.to_str())
            .unwrap_or("unknown-run")
            .to_string()
    });
    let drafts = read_patch_draft_artifact(run_dir)?;
    if !drafts.drafts.iter().any(|draft| draft.id == patch_draft_id) {
        return Err(anyhow!(
            "patch draft id not found for sandbox: {}",
            patch_draft_id
        ));
    }
    let layout = PatchSandboxLayout {
        sandbox_id: patch_draft_id.to_string(),
        patch_draft_id: patch_draft_id.to_string(),
        lifecycle_state: PatchSandboxState::Planned,
        sandbox_root: format!("sandbox/{patch_draft_id}"),
        worktree_path: format!("sandbox/{patch_draft_id}/worktree"),
        evidence_path: format!("sandbox/{patch_draft_id}/evidence"),
        plan_path: format!("sandbox/{patch_draft_id}/plan.json"),
    };
    let plan = PatchSandboxPlan {
        schema_version: "1".to_string(),
        run_id,
        layout,
        verification_commands: vec!["cargo fmt --check".to_string(), "cargo test".to_string()],
    };
    plan.validate(run_dir)?;
    Ok(plan)
}
pub fn create_patch_sandbox_layout(
    run_dir: impl AsRef<Path>,
    patch_draft_id: &str,
) -> Result<PatchSandboxPlan> {
    let run_dir = run_dir.as_ref();
    let plan = plan_patch_sandbox(run_dir, patch_draft_id)?;
    let root = run_dir.join(&plan.layout.sandbox_root);
    let worktree = run_dir.join(&plan.layout.worktree_path);
    let evidence = run_dir.join(&plan.layout.evidence_path);
    ensure_path_inside(run_dir, &root)?;
    // Reject a pre-existing symlinked worktree/evidence leaf before create_dir_all
    // would follow it: otherwise patch application could write through the symlink
    // into the primary filesystem instead of the isolated run sandbox.
    for leaf in [&worktree, &evidence] {
        if leaf
            .symlink_metadata()
            .map(|metadata| metadata.file_type().is_symlink())
            .unwrap_or(false)
        {
            return Err(anyhow!(
                "patch sandbox path must not be a symlink: {}",
                leaf.display()
            ));
        }
    }
    ensure_path_inside(run_dir, &worktree)?;
    ensure_path_inside(run_dir, &evidence)?;
    fs::create_dir_all(&worktree).context("failed to create patch sandbox worktree")?;
    fs::create_dir_all(&evidence).context("failed to create patch sandbox evidence")?;
    let plan_path = run_dir.join(&plan.layout.plan_path);
    write_json_atomic(&plan_path, &json!(plan))?;
    Ok(plan)
}
pub fn normalize_evolve_comparison_classification(classification: &str) -> &'static str {
    match classification {
        "improved" => "improved",
        "regressed" => "regressed",
        "no_change" => "no_change",
        _ => "no_change",
    }
}
pub fn evolve_run_reference(run_dir: &Path) -> Result<EvolveRunReference> {
    let run = read_json_value(run_dir.join("run.json"))?;
    let run_id = run
        .get("id")
        .and_then(|value| value.as_str())
        .ok_or_else(|| anyhow!("evolve rerun baseline run.json missing id"))?
        .to_string();
    for relative in ["run.json", "verdict.json", "evidence/index.json"] {
        let path = run_dir.join(relative);
        if !path.is_file() {
            return Err(anyhow!(
                "evolve rerun baseline is missing required artifact {}",
                path.display()
            ));
        }
    }
    Ok(EvolveRunReference {
        run_id,
        run_path: "run.json".to_string(),
        verdict_path: "verdict.json".to_string(),
        evidence_index_path: "evidence/index.json".to_string(),
    })
}
pub fn resolve_patch_sandbox_run_dir(path: &Path) -> Result<PathBuf> {
    if path.is_dir() {
        return Ok(path.to_path_buf());
    }
    if path.file_name().and_then(|name| name.to_str()) == Some("patch-drafts.json") {
        return path
            .parent()
            .and_then(Path::parent)
            .map(Path::to_path_buf)
            .ok_or_else(|| anyhow!("patch draft path must be under <run>/mutation/"));
    }
    Err(anyhow!(
        "evolve sandbox expects a run directory or <run>/mutation/patch-drafts.json"
    ))
}
pub fn git_repo_root() -> Result<PathBuf> {
    let output = Command::new("git")
        .args(["rev-parse", "--show-toplevel"])
        .output()
        .context("failed to locate git repository root")?;
    if !output.status.success() {
        return Err(anyhow!(
            "failed to locate git repository root: {}",
            String::from_utf8_lossy(&output.stderr).trim()
        ));
    }
    Ok(PathBuf::from(String::from_utf8(output.stdout)?.trim()))
}
pub fn git_status_short(repo_root: &Path) -> Result<String> {
    let output = Command::new("git")
        .args(["status", "--short", "--untracked-files=no"])
        .current_dir(repo_root)
        .output()
        .context("failed to inspect primary git status")?;
    if !output.status.success() {
        return Err(anyhow!(
            "failed to inspect primary git status: {}",
            String::from_utf8_lossy(&output.stderr).trim()
        ));
    }
    Ok(String::from_utf8(output.stdout)?)
}
pub fn copy_repo_tracked_files(repo_root: &Path, worktree: &Path) -> Result<()> {
    let output = Command::new("git")
        .args(["ls-files", "-z"])
        .current_dir(repo_root)
        .output()
        .context("failed to list tracked repository files")?;
    if !output.status.success() {
        return Err(anyhow!(
            "failed to list tracked repository files: {}",
            String::from_utf8_lossy(&output.stderr).trim()
        ));
    }
    for raw in output.stdout.split(|byte| *byte == 0) {
        if raw.is_empty() {
            continue;
        }
        let relative = std::str::from_utf8(raw).context("tracked path is not valid UTF-8")?;
        let source = repo_root.join(relative);
        let target = worktree.join(relative);
        ensure_path_inside(worktree, &target)?;
        if let Some(parent) = target.parent() {
            fs::create_dir_all(parent)
                .with_context(|| format!("failed to create {}", parent.display()))?;
        }
        fs::copy(&source, &target).with_context(|| {
            format!(
                "failed to copy tracked file {} to sandbox {}",
                source.display(),
                target.display()
            )
        })?;
    }
    Ok(())
}
pub fn run_sandbox_verification_command(
    worktree: &Path,
    evidence: &Path,
    index: usize,
    command: &str,
) -> Result<PatchSandboxVerificationOutput> {
    let output = Command::new("sh")
        .arg("-c")
        .arg(command)
        .current_dir(worktree)
        .output()
        .with_context(|| format!("failed to run sandbox verification command `{command}`"))?;
    let stdout_path = evidence.join(format!("verification-{index}-stdout.txt"));
    let stderr_path = evidence.join(format!("verification-{index}-stderr.txt"));
    fs::write(&stdout_path, &output.stdout)
        .with_context(|| format!("failed to write {}", stdout_path.display()))?;
    fs::write(&stderr_path, &output.stderr)
        .with_context(|| format!("failed to write {}", stderr_path.display()))?;
    Ok(PatchSandboxVerificationOutput {
        command: command.to_string(),
        status: output.status.code().unwrap_or(-1),
        stdout_path: run_relative_path_from_sandbox_worktree(worktree, &stdout_path)?,
        stderr_path: run_relative_path_from_sandbox_worktree(worktree, &stderr_path)?,
    })
}
pub fn run_relative_path(run_dir: &Path, path: &Path) -> Result<String> {
    path.strip_prefix(run_dir)
        .with_context(|| format!("{} is outside run directory", path.display()))?
        .to_str()
        .map(str::to_string)
        .ok_or_else(|| anyhow!("run-relative path is not valid UTF-8"))
}
pub fn run_relative_path_from_sandbox_worktree(worktree: &Path, path: &Path) -> Result<String> {
    let run_dir = worktree
        .parent()
        .and_then(Path::parent)
        .and_then(Path::parent)
        .ok_or_else(|| anyhow!("sandbox worktree is not under a run directory"))?;
    run_relative_path(run_dir, path)
}
pub fn list_mutation_proposals(run_dir: impl AsRef<Path>) -> Result<Vec<MutationProposal>> {
    Ok(read_mutation_proposals(run_dir)?.proposals)
}
pub fn read_mutation_proposals(run_dir: impl AsRef<Path>) -> Result<MutationProposalIndex> {
    let path = run_dir.as_ref().join("mutation/proposals.json");
    if !path.exists() {
        return Ok(MutationProposalIndex::default());
    }
    let input = fs::read_to_string(&path)
        .with_context(|| format!("failed to read mutation proposals {}", path.display()))?;
    let index: MutationProposalIndex = serde_json::from_str(&input)
        .with_context(|| format!("failed to parse mutation proposals {}", path.display()))?;
    index
        .validate()
        .with_context(|| format!("failed to validate mutation proposals {}", path.display()))?;
    Ok(index)
}
pub fn write_mutation_proposals(
    run_dir: impl AsRef<Path>,
    index: &MutationProposalIndex,
) -> Result<()> {
    index.validate()?;
    let dir = run_dir.as_ref().join("mutation");
    fs::create_dir_all(&dir).context("failed to create mutation directory")?;
    write_json_atomic(&dir.join("proposals.json"), &json!(index))
}
pub fn show_journal(run_dir: impl AsRef<Path>) -> Result<String> {
    fs::read_to_string(run_dir.as_ref().join("journal.md")).context("failed to read journal")
}
pub fn render_evolve_rerun_delta_journal_section(
    run_dir: &Path,
    proposals: &[MutationProposal],
) -> String {
    let comparison = read_dashboard_comparison(run_dir);
    if !comparison.present || comparison.artifacts.is_empty() {
        return String::new();
    }
    let mut out = String::new();
    out.push_str("\n## Mutation loop summary\n\n");
    out.push_str(
        "- Summary shape: hypothesis → failing gate → evidence → proposal → rerun delta.\n",
    );
    out.push_str("- Four-gate rerun delta:\n");
    for artifact in &comparison.artifacts {
        let Some(value) = &artifact.value else {
            continue;
        };
        if let Some(gates) = value
            .get("fourGate")
            .and_then(|four_gate| four_gate.get("gates"))
            .and_then(|gates| gates.as_array())
        {
            for gate in gates {
                let gate_name = gate
                    .get("gate")
                    .and_then(|value| value.as_str())
                    .unwrap_or("unknown");
                let before = gate
                    .get("before")
                    .and_then(|value| value.as_str())
                    .unwrap_or("unknown");
                let after = gate
                    .get("after")
                    .and_then(|value| value.as_str())
                    .unwrap_or("unknown");
                let transition = gate
                    .get("transition")
                    .and_then(|value| value.as_str())
                    .unwrap_or("unknown");
                out.push_str(&format!(
                    "  - `{gate_name}`: `{before}` -> `{after}` (`{transition}`) via `{}`.\n",
                    artifact.path
                ));
            }
        }
    }
    for (index, proposal) in proposals.iter().enumerate() {
        let Some(rationale) = &proposal.rationale else {
            continue;
        };
        let gate = rationale
            .failing_gate_category
            .as_ref()
            .map(mutation_proposal_gate_category_label)
            .unwrap_or("unknown");
        let evidence = rationale
            .justifying_evidence_ref
            .as_deref()
            .unwrap_or("missing");
        out.push_str(&format!(
            "- proposal `mutation-{}` (`{}`): hypothesis `{}`; failing gate `{}`; evidence `{}`; rerun delta above remains manual-review evidence only.\n",
            index + 1,
            proposal.id,
            rationale.expected_effect,
            gate,
            evidence
        ));
    }
    out.push('\n');
    out
}
pub fn render_visual_semantic_gate_journal_section(verdict: &serde_json::Value) -> String {
    let mut out = String::new();
    if let Some(categories) = verdict
        .get("gateCategories")
        .and_then(|value| value.as_object())
    {
        out.push_str("## Four-Gate Verdict Categories\n\n");
        for gate in ["mechanical", "runtime", "visual", "semantic"] {
            let Some(category) = categories.get(gate) else {
                continue;
            };
            let declared = category
                .get("declared")
                .and_then(|value| value.as_bool())
                .unwrap_or(false);
            let status = category
                .get("status")
                .and_then(|value| value.as_str())
                .unwrap_or("unknown");
            let result_count = category
                .get("resultCount")
                .and_then(|value| value.as_u64())
                .unwrap_or(0);
            let failure_count = category
                .get("failureCount")
                .and_then(|value| value.as_u64())
                .unwrap_or(0);
            out.push_str(&format!(
                "- `{gate}`: `{status}` (declared: `{declared}`, results: `{result_count}`, failures: `{failure_count}`)\n"
            ));
        }
        if let Some(aggregation) = categories.get("aggregation") {
            let operator = aggregation
                .get("operator")
                .and_then(|value| value.as_str())
                .unwrap_or("declared-gate-and");
            let undeclared = aggregation
                .get("undeclaredGatePolicy")
                .and_then(|value| value.as_str())
                .unwrap_or("neutral");
            out.push_str(&format!(
                "- Aggregation: `{operator}`; undeclared gate policy: `{undeclared}`.\n"
            ));
        }
        out.push('\n');
    }

    let visual_failures = verdict
        .get("visual")
        .and_then(|value| value.as_array())
        .into_iter()
        .flatten()
        .filter(|gate| gate.get("state").and_then(|value| value.as_str()) != Some("pass"))
        .collect::<Vec<_>>();
    let semantic_failures = verdict
        .get("semantic")
        .and_then(|value| value.as_array())
        .into_iter()
        .flatten()
        .filter(|gate| gate.get("state").and_then(|value| value.as_str()) != Some("pass"))
        .collect::<Vec<_>>();
    if visual_failures.is_empty() && semantic_failures.is_empty() {
        return out;
    }

    out.push_str("## Visual/Semantic Gate Observations\n\n");
    for gate in visual_failures {
        let state = gate
            .get("state")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown");
        let reason = gate
            .get("reason")
            .and_then(|value| value.as_str())
            .unwrap_or("visual gate did not pass");
        let evidence = gate
            .get("comparisonRef")
            .or_else(|| gate.get("comparison_ref"))
            .and_then(|value| value.as_str())
            .unwrap_or("unknown-evidence");
        out.push_str(&format!(
            "- Visual `{state}`: {reason} (evidence `{evidence}`)\n"
        ));
        out.push_str(&format!(
            "  - Next-step hypothesis: inspect `{evidence}` and its screenshot refs before changing visual acceptance.\n"
        ));
    }
    for gate in semantic_failures {
        let state = gate
            .get("state")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown");
        let invariant = gate
            .get("invariantId")
            .or_else(|| gate.get("invariant_id"))
            .and_then(|value| value.as_str())
            .unwrap_or("unknown-invariant");
        let target = gate
            .get("targetPath")
            .or_else(|| gate.get("target_path"))
            .and_then(|value| value.as_str())
            .unwrap_or("unknown-target");
        let reason = gate
            .get("reason")
            .and_then(|value| value.as_str())
            .unwrap_or("semantic gate did not pass");
        let evidence = gate
            .get("modelRef")
            .or_else(|| gate.get("model_ref"))
            .and_then(|value| value.as_str())
            .or_else(|| {
                gate.get("evidenceRefs")
                    .or_else(|| gate.get("evidence_refs"))
                    .and_then(|value| value.as_array())
                    .and_then(|refs| refs.first())
                    .and_then(|value| value.as_str())
            })
            .unwrap_or("unknown-evidence");
        out.push_str(&format!(
            "- Semantic `{state}`: invariant `{invariant}` over `{target}` — {reason} (evidence `{evidence}`)\n"
        ));
        out.push_str(&format!(
            "  - Next-step hypothesis: inspect `{evidence}` and the declared invariant before changing scenario semantics.\n"
        ));
    }
    out.push('\n');
    out
}
pub fn read_dashboard_scenario_assertions(
    scenario_results: &[RunDashboardArtifact],
) -> RunDashboardScenarioAssertions {
    #[derive(Default)]
    struct TargetBuilder {
        total_count: usize,
        passed_count: usize,
        failed_count: usize,
        evidence_refs: Vec<String>,
    }

    let mut total_count = 0usize;
    let mut passed_count = 0usize;
    let mut failed_count = 0usize;
    let mut scene3d_count = 0usize;
    let mut scene3d_failed_count = 0usize;
    let mut evidence_refs = Vec::new();
    let mut targets: BTreeMap<String, TargetBuilder> = BTreeMap::new();

    for result in scenario_results
        .iter()
        .filter_map(|artifact| artifact.value.as_ref())
    {
        let Some(assertions) = result.get("assertions").and_then(|value| value.as_array()) else {
            continue;
        };
        for assertion in assertions {
            let target = assertion
                .get("target")
                .and_then(|value| value.as_str())
                .unwrap_or("unknown")
                .to_string();
            let passed = assertion.get("passed").and_then(|value| value.as_bool()) == Some(true);
            total_count += 1;
            if passed {
                passed_count += 1;
            } else {
                failed_count += 1;
            }
            if target.starts_with("scene3d_") {
                scene3d_count += 1;
                if !passed {
                    scene3d_failed_count += 1;
                }
            }
            let builder = targets.entry(target).or_default();
            builder.total_count += 1;
            if passed {
                builder.passed_count += 1;
            } else {
                builder.failed_count += 1;
            }
            if let Some(reference) = assertion
                .get("evidence_ref")
                .and_then(|value| value.as_str())
            {
                builder.evidence_refs.push(reference.to_string());
                if assertion
                    .get("target")
                    .and_then(|value| value.as_str())
                    .is_some_and(|target| target.starts_with("scene3d_"))
                {
                    evidence_refs.push(reference.to_string());
                }
            }
        }
    }

    dedupe_sorted(&mut evidence_refs);
    let targets = targets
        .into_iter()
        .map(|(id, mut target)| {
            dedupe_sorted(&mut target.evidence_refs);
            RunDashboardScenarioAssertionTarget {
                id,
                total_count: target.total_count,
                passed_count: target.passed_count,
                failed_count: target.failed_count,
                evidence_refs: target.evidence_refs,
            }
        })
        .collect::<Vec<_>>();

    RunDashboardScenarioAssertions {
        present: total_count > 0,
        empty_state: if total_count > 0 {
            String::new()
        } else {
            "No scenario assertion results were found in scenario-result artifacts.".to_string()
        },
        total_count,
        passed_count,
        failed_count,
        scene3d_count,
        scene3d_failed_count,
        evidence_refs,
        targets,
        boundary: "Display-only assertion summary; browser/dashboard surfaces do not perform trusted writes or production 3D engine validation.".to_string(),
    }
}
pub fn read_dashboard_behavior_assertions(
    result_artifacts: &[RunDashboardArtifact],
) -> RunDashboardBehaviorAssertions {
    let mut suites = Vec::new();
    let mut total_count = 0usize;
    let mut passed_count = 0usize;
    let mut failed_count = 0usize;
    let mut malformed_count = 0usize;
    let mut result_refs = Vec::new();
    let mut evidence_refs = Vec::new();

    for artifact in result_artifacts {
        if !artifact.exists || artifact.read_error.is_some() {
            malformed_count += 1;
            continue;
        }
        let Some(value) = artifact.value.as_ref() else {
            malformed_count += 1;
            continue;
        };
        let assertions = value
            .get("assertions")
            .and_then(|value| value.as_array())
            .cloned()
            .unwrap_or_default();
        let mut suite_passed = 0usize;
        let mut suite_failed = 0usize;
        let mut suite_failures = Vec::new();
        for assertion in assertions {
            total_count += 1;
            let status = assertion
                .get("status")
                .and_then(|value| value.as_str())
                .unwrap_or("unknown");
            if status == "passed" {
                passed_count += 1;
                suite_passed += 1;
            } else {
                failed_count += 1;
                suite_failed += 1;
                suite_failures.push(RunDashboardBehaviorAssertionFailure {
                    assertion_id: assertion
                        .get("assertionId")
                        .and_then(|value| value.as_str())
                        .unwrap_or("unknown")
                        .to_string(),
                    message: assertion
                        .get("message")
                        .and_then(|value| value.as_str())
                        .unwrap_or("No behavior assertion message recorded.")
                        .to_string(),
                });
            }
        }
        result_refs.push(artifact.path.clone());
        let evidence_ref = value
            .get("evidenceRef")
            .and_then(|value| value.as_str())
            .map(str::to_string);
        if let Some(reference) = &evidence_ref {
            evidence_refs.push(reference.clone());
        }
        suites.push(RunDashboardBehaviorAssertionSuite {
            suite_id: value
                .get("suiteId")
                .and_then(|value| value.as_str())
                .unwrap_or("unknown")
                .to_string(),
            scenario_id: value
                .get("scenarioId")
                .and_then(|value| value.as_str())
                .map(str::to_string),
            status: value
                .get("status")
                .and_then(|value| value.as_str())
                .unwrap_or("unknown")
                .to_string(),
            result_ref: artifact.path.clone(),
            evidence_ref,
            total_count: suite_passed + suite_failed,
            passed_count: suite_passed,
            failed_count: suite_failed,
            failures: suite_failures,
        });
    }

    dedupe_sorted(&mut result_refs);
    dedupe_sorted(&mut evidence_refs);
    RunDashboardBehaviorAssertions {
        present: !result_artifacts.is_empty(),
        empty_state: if result_artifacts.is_empty() {
            "No behavior assertion result artifacts were found.".to_string()
        } else {
            String::new()
        },
        result_count: result_artifacts.len(),
        malformed_count,
        total_count,
        passed_count,
        failed_count,
        result_refs,
        evidence_refs,
        suites,
        boundary: "Display-only structured behavior assertion summary; no arbitrary script execution, dynamic imports, browser trusted writes, command bridge, or production scripting API.".to_string(),
    }
}
pub fn render_authoring_governance_journal_section(
    proposals: &[MutationProposal],
    reviews: &[MutationReviewDecision],
    applications: &[SceneOnlyMutationApplicationRecord],
    application_read_error: Option<&str>,
    visual_applications: (&[VisualEditDraftApplicationRecord], Option<&str>),
    comparison: &RunDashboardComparison,
    promotions: &[RegressionPromotionPackResult],
) -> String {
    let mut out = String::new();
    out.push_str(
        "
## Authoring Governance Lifecycle

",
    );
    out.push_str(
        "- Schema: `journal-authoring-governance-v2`
",
    );
    out.push_str("- Boundary: deterministic local evidence only; no AI/network summary, mutation application, browser write, command bridge, or hosted audit service.

");

    out.push_str(
        "### Proposal Quality

",
    );
    if proposals.is_empty() {
        out.push_str(
            "- No mutation proposals recorded.
",
        );
    } else {
        for proposal in proposals {
            out.push_str(&format!(
                "- `{}`: status `{}` target `{}` path `{}` evidence `{}` verdict `{}`
",
                proposal.id,
                proposal.status,
                proposal.target,
                proposal.path,
                proposal.evidence_id,
                proposal.verdict_status
            ));
            if let Some(rationale) = &proposal.rationale {
                out.push_str(&format!(
                    "  - Rationale: `{}`; expected effect: {}; allowed mutation: `{:?}`; confidence: `{:?}`
",
                    rationale.failure_classification,
                    rationale.expected_effect,
                    rationale.allowed_mutation_type,
                    rationale.confidence
                ));
                out.push_str(&format!(
                    "  - Evidence refs: artifacts {}; scenarios {}; verdicts {}
",
                    join_or_none(&rationale.evidence_artifact_ids),
                    join_or_none(&rationale.scenario_result_refs),
                    join_or_none(&rationale.verdict_refs)
                ));
                if let (Some(gate), Some(evidence_state), Some(bounded_type)) = (
                    &rationale.failing_gate_category,
                    &rationale.evidence_state,
                    &rationale.bounded_mutation_type,
                ) {
                    out.push_str(&format!(
                        "  - Evidence-linked gate `{}` via `{}`; evidence state `{}`; bounded type `{}`
",
                        mutation_proposal_gate_category_label(gate),
                        rationale
                            .justifying_evidence_ref
                            .as_deref()
                            .unwrap_or("missing"),
                        mutation_proposal_evidence_state_label(evidence_state),
                        mutation_proposal_bounded_type_label(bounded_type)
                    ));
                }
            } else {
                out.push_str(
                    "  - Rationale: missing; proposal quality evidence has not been attached.
",
                );
            }
        }
    }

    out.push_str(
        "
### Review Decisions

",
    );
    if reviews.is_empty() {
        out.push_str(
            "- No review decisions recorded; accepted/rejected/deferred status is unavailable.
",
        );
    } else {
        for decision in reviews {
            let status = decision.decision_status.as_ref().unwrap_or(&decision.state);
            out.push_str(&format!(
                "- `{}`: `{:?}` proposal `{}` patch draft `{}` reviewer `{}` (`{:?}`)
",
                decision.id,
                status,
                decision.proposal_id.as_deref().unwrap_or("unlinked"),
                decision.patch_draft_id,
                decision.reviewer,
                decision
                    .reviewer_type
                    .as_ref()
                    .unwrap_or(&MutationReviewReviewerType::Human)
            ));
            out.push_str(&format!(
                "  - Reason: {}
",
                decision.reason
            ));
            out.push_str(&format!(
                "  - Evidence refs: {}
",
                join_or_none(&decision.evidence_refs)
            ));
            if let Some(checklist) = &decision.guardrail_checklist {
                out.push_str(&format!(
                    "  - Guardrails: record_only={} accepted_does_not_apply={} browser_read_only={} evidence_refs_checked={}
",
                    checklist.proposal_is_record_only,
                    checklist.accepted_does_not_apply,
                    checklist.browser_read_only,
                    checklist.evidence_refs_checked
                ));
            }
        }
    }

    out.push_str(
        "
### Review-Gated Applications

",
    );
    if let Some(error) = application_read_error {
        out.push_str(&format!(
            "- Scene application artifact is present but malformed: {}\n",
            error
        ));
    } else if applications.is_empty() {
        out.push_str(
            "- No review-gated scene applications recorded.
",
        );
    } else {
        for application in applications {
            out.push_str(&format!(
                "- `{}`: status `{}` proposal `{}` decision `{}` transaction `{}` target `{}`
",
                application.id,
                application.status,
                application.proposal_id,
                application
                    .review_decision_id
                    .as_deref()
                    .unwrap_or("unreviewed"),
                application.transaction_id,
                application.target_scene_path
            ));
            out.push_str(&format!(
                "  - Transaction artifact: `{}`; before `{}`; after `{}`
",
                application.transaction_artifact_path,
                application.before_scene_hash.value,
                application.after_scene_hash.value
            ));
            if let Some(project) = &application.project {
                out.push_str(&format!(
                    "  - Project: `{}` manifest `{}` scene `{}`
",
                    project.project_id, project.manifest_path, project.scene_path
                ));
            }
        }
    }

    out.push_str(
        "
### Visual Draft Applications

",
    );
    let (visual_applications, visual_application_read_error) = visual_applications;
    if let Some(error) = visual_application_read_error {
        out.push_str(&format!(
            "- Visual draft application artifact is present but malformed: {}\n",
            error
        ));
    } else if visual_applications.is_empty() {
        out.push_str(
            "- No visual draft applications recorded.
",
        );
    } else {
        for application in visual_applications {
            out.push_str(&format!(
                "- `{}`: status `{}` draft `{}` proposal `{}` patch draft `{}` decision `{}` transaction `{}`
",
                application.id,
                application.status,
                application.draft_id,
                application.proposal_id,
                application.patch_draft_id,
                application.review_decision_id,
                application.transaction_id
            ));
            out.push_str(&format!(
                "  - Transaction artifact: `{}`; target scene `{}`; before `{}`; after `{}`
",
                application.transaction_artifact_path,
                application.target_scene_path,
                application.before_scene_hash.value,
                application.after_scene_hash.value
            ));
            out.push_str(&format!(
                "  - Rerun context is inert/display-only: `{}`\n",
                application.command_context.command
            ));
        }
    }

    out.push_str(
        "
### Rerun and Compare

",
    );
    if !comparison.present {
        out.push_str(&format!("- {}\n", comparison.empty_state));
    } else if comparison.artifacts.is_empty() {
        out.push_str(
            "- Comparison read model is present but contains no artifacts.
",
        );
    } else {
        for artifact in &comparison.artifacts {
            out.push_str(&format!(
                "- `{}`: classification `{}` before `{}` after `{}` path `{}`
",
                artifact.id,
                artifact.classification.as_deref().unwrap_or("unknown"),
                artifact.before_run_id.as_deref().unwrap_or("unknown"),
                artifact.after_run_id.as_deref().unwrap_or("unknown"),
                artifact.path
            ));
            if let Some(error) = &artifact.read_error {
                out.push_str(&format!("  - Read error: {}\n", error));
            }
            out.push_str(&format!(
                "  - Evidence refs: {}; unsupported: {}
",
                join_or_none(&artifact.evidence_refs),
                join_or_none(&artifact.unsupported)
            ));
            out.push_str(&render_four_gate_delta_journal_lines(
                &artifact.value,
                proposals,
            ));
        }
    }

    out.push_str(
        "
### Regression Promotion Status

",
    );
    if promotions.is_empty() {
        out.push_str(
            "- No regression promotions recorded.
",
        );
    } else {
        for promotion in promotions {
            out.push_str(&format!(
                "- `{}`: scenario `{}` pack `{}` dry-run `{}` record `{}`
",
                promotion.id,
                promotion.scenario_id,
                promotion.target.scenario_pack_id,
                promotion.dry_run,
                promotion
                    .record_path
                    .as_deref()
                    .unwrap_or("dry-run/no record")
            ));
            out.push_str(&format!(
                "  - Source run `{}` verdict `{}`; before `{}`; after `{}`
",
                promotion.source_run.run_id,
                promotion.source_run.verdict_path,
                promotion.before_hash.value,
                promotion.after_hash.value
            ));
        }
    }
    out
}
pub fn render_four_gate_delta_journal_lines(
    value: &Option<serde_json::Value>,
    proposals: &[MutationProposal],
) -> String {
    let Some(value) = value else {
        return String::new();
    };
    let Some(deltas) = value
        .get("fourGateDeltas")
        .and_then(|value| value.as_array())
    else {
        return String::new();
    };
    let mut out = String::new();
    for delta in deltas {
        let gate = delta
            .get("gate")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown");
        let transition = delta
            .get("transition")
            .and_then(|value| value.as_str())
            .unwrap_or("changed");
        let before = delta
            .get("beforeStatus")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown");
        let after = delta
            .get("afterStatus")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown");
        out.push_str(&format!(
            "  - rerun delta `{gate}`: `{transition}` (`{before}` -> `{after}`)
"
        ));
    }
    if let Some(proposal) = proposals.first() {
        let (failed_gate, evidence, hypothesis) = proposal
            .rationale
            .as_ref()
            .map(|rationale| {
                (
                    rationale
                        .failing_gate_category
                        .as_ref()
                        .map(mutation_proposal_gate_category_label)
                        .unwrap_or("unknown"),
                    rationale
                        .justifying_evidence_ref
                        .as_deref()
                        .unwrap_or(proposal.evidence_id.as_str()),
                    rationale.expected_effect.as_str(),
                )
            })
            .unwrap_or((
                "unknown",
                proposal.evidence_id.as_str(),
                proposal.reason.as_str(),
            ));
        out.push_str(&format!(
            "  - Next-step hypothesis: {hypothesis}
  - Evidence-linked gate: `{failed_gate}` evidence `{evidence}` proposal `{}`; rerun deltas above are manual-review evidence only.
",
            proposal.id
        ));
    }
    out
}
pub fn join_or_none(values: &[String]) -> String {
    if values.is_empty() {
        "none".to_string()
    } else {
        values.join(", ")
    }
}
pub fn render_review_decision_journal_section(reviews: &[MutationReviewDecision]) -> String {
    let mut out = String::new();
    out.push_str(
        "
## Review Decisions

",
    );
    if reviews.is_empty() {
        out.push_str(
            "- No review decisions recorded.
",
        );
        return out;
    }
    for decision in reviews {
        let status = decision.decision_status.as_ref().unwrap_or(&decision.state);
        out.push_str(&format!(
            "- `{}`: `{:?}` for proposal `{}` patch draft `{}` by `{}` (`{:?}`)
",
            decision.id,
            status,
            decision.proposal_id.as_deref().unwrap_or("unlinked"),
            decision.patch_draft_id,
            decision.reviewer,
            decision
                .reviewer_type
                .as_ref()
                .unwrap_or(&MutationReviewReviewerType::Human),
        ));
        out.push_str(&format!(
            "  - Reason: {}
",
            decision.reason
        ));
        out.push_str(&format!(
            "  - Evidence refs: {}
",
            if decision.evidence_refs.is_empty() {
                "none".to_string()
            } else {
                decision.evidence_refs.join(", ")
            }
        ));
        if let Some(checklist) = &decision.guardrail_checklist {
            out.push_str(&format!(
                "  - Guardrails: record_only={} accepted_does_not_apply={} browser_read_only={} evidence_refs_checked={}
",
                checklist.proposal_is_record_only,
                checklist.accepted_does_not_apply,
                checklist.browser_read_only,
                checklist.evidence_refs_checked
            ));
        }
    }
    out
}
pub fn render_regression_promotion_journal_section(
    promotions: &[RegressionPromotionPackResult],
) -> String {
    let mut out = String::new();
    out.push_str(
        "
## Regression Promotions

",
    );
    if promotions.is_empty() {
        out.push_str(
            "- No regression promotions recorded.
",
        );
        return out;
    }
    for promotion in promotions {
        out.push_str(&format!(
            "- `{}`: scenario `{}` -> pack `{}` (dry-run: `{}`, before `{}`, after `{}`)\n",
            promotion.id,
            promotion.scenario_id,
            promotion.target.scenario_pack_id,
            promotion.dry_run,
            promotion.before_hash.value,
            promotion.after_hash.value
        ));
        if let Some(record_path) = &promotion.record_path {
            out.push_str(&format!("  - Record: `{record_path}`\n"));
        }
    }
    out
}
